#include <bits/stdc++.h>
using namespace std;
int d[4][2]={{0,1},{-1,0},{0,-1},{1,0}};
int n,m,h[102][102],dist[102][102],ans=1;
int dfs(int x,int y){
    if(dist[x][y])
        return dist[x][y];
    dist[x][y]=1;
    for(int i=0;i<4;i++){
        int xx=x+d[i][0],yy=y+d[i][1];
        if(xx>0 && yy>0 && xx<=n && yy<=m && h[xx][yy]>h[x][y])
            dist[x][y]=max(dist[x][y],dfs(xx,yy)+1);
    }
    ans=max(ans,dist[x][y]);
    return dist[x][y];
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            scanf("%d",&h[i][j]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            if(!dist[i][j])
                dfs(i,j);
    printf("%d",ans);
    return 0;
}
